const correlationId = `fb-daily-${new Date().toISOString().slice(0,10)}-${Math.floor(Math.random()*1e6)}`;
const yesterday = new Date(Date.now() - 86400000).toISOString().slice(0,10);
return [{ json: {
  correlationId,
  yesterday,
  adAccountId: '__REPLACE_ME__AD_ACCOUNT_ID__',
  startedAt: new Date().toISOString()
}}];

const items = $input.first().json?.data || [];
return items.map(c => ({ json: {
  correlationId: $node['Stamp correlation'].json.correlationId,
  yesterday: $node['Stamp correlation'].json.yesterday,
  adAccountId: $node['Stamp correlation'].json.adAccountId,
  campaignId: c.id,
  campaignName: c.name,
  status: c.status,
  dailyBudgetMinor: Number(c.daily_budget || 0),
  objective: c.objective
}}));

const row = $json?.data?.[0] || {};
const conversions = (row.actions || []).find(a => a.action_type === 'offsite_conversion.fb_pixel_purchase')?.value;
const revenue = (row.action_values || []).find(a => a.action_type === 'offsite_conversion.fb_pixel_purchase')?.value;
const spend = Number(row.spend || 0);
const convInt = Number(conversions || 0);
const revNum = Number(revenue || 0);
const cpa = convInt > 0 ? spend / convInt : null;
const roas = spend > 0 ? revNum / spend : null;
return [{ json: {
  correlationId: $node['Stamp correlation'].json.correlationId,
  yesterday: $node['Stamp correlation'].json.yesterday,
  campaignId: $json.campaignId,
  campaignName: $json.campaignName,
  dailyBudgetMinor: $json.dailyBudgetMinor,
  spend,
  impressions: Number(row.impressions || 0),
  clicks: Number(row.clicks || 0),
  ctr: Number(row.ctr || 0),
  cpm: Number(row.cpm || 0),
  conversions: convInt,
  revenue: revNum,
  cpa,
  roas
}}];
